const allItems = $input.all();
const extractItem = allItems[0]?.json || {};
const cert = extractItem.data || extractItem;

const analysisItem = allItems[1]?.json || {};
const complianceCheck = analysisItem.answer || analysisItem.markdown || analysisItem.text || '';

const triggerData = $('New Certificate').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

// Expiration calculation
const expirationDate = cert.expirationDate || '';
let daysUntilExpiry = null;
let expiryStatus = 'Unknown';
let riskLevel = 'Unknown';

if (expirationDate) {
  const expDate = new Date(expirationDate);
  const today   = new Date();
  daysUntilExpiry = Math.floor((expDate - today) / (1000 * 60 * 60 * 24));

  if (daysUntilExpiry < 0) {
    expiryStatus = 'EXPIRED';
    riskLevel = 'Critical';
  } else if (daysUntilExpiry <= 30) {
    expiryStatus = 'Expiring Soon (≤30 days)';
    riskLevel = 'High';
  } else if (daysUntilExpiry <= 90) {
    expiryStatus = 'Expiring Soon (≤90 days)';
    riskLevel = 'Medium';
  } else {
    expiryStatus = 'Valid';
    riskLevel = 'Low';
  }
}

// Override if certificate is suspended/withdrawn
const certStatus = (cert.certificateStatus || '').toLowerCase();
if (certStatus.includes('suspend') || certStatus.includes('withdraw')) {
  expiryStatus = 'SUSPENDED/WITHDRAWN';
  riskLevel = 'Critical';
}

// Non-conformities risk bump
const majorNC = parseInt(cert.majorNonConformities) || 0;
if (majorNC > 0 && riskLevel === 'Low') riskLevel = 'Medium';
if (majorNC > 2) riskLevel = 'High';

// Parse compliance notes from AI
const complianceNotes = complianceCheck.slice(0, 300) || 'N/A';

return [{ json: {
  supplierName:       cert.supplierName        || 'Unknown',
  supplierCountry:    cert.supplierCountry     || 'N/A',
  supplierCity:       cert.supplierCity        || 'N/A',
  certificateType:    cert.certificateType     || 'Unknown',
  certificateNumber:  cert.certificateNumber   || 'N/A',
  certificateStatus:  cert.certificateStatus   || 'N/A',
  issueDate:          cert.issueDate           || 'N/A',
  expirationDate,
  daysUntilExpiry,
  expiryStatus,
  riskLevel,
  certifierName:      cert.certifierName       || 'N/A',
  standardVersion:    cert.standardVersion     || 'N/A',
  scopeDescription:   cert.scopeDescription    || 'N/A',
  productCategories:  cert.productCategories   || 'N/A',
  majorNonConformities: majorNC,
  minorNonConformities: parseInt(cert.minorNonConformities) || 0,
  auditFindingsSummary: cert.auditFindingsSummary || 'None',
  certificateGrade:   cert.certificateGrade    || 'N/A',
  complianceNotes,
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

